mapper.select:
SELECT COALESCE(p.content, '')
FROM post p
WHERE p.id = #{postId}
  AND p.member_id = #{memberId}
  AND p.deleted_at IS NULL
  AND EXISTS (
      SELECT 1 FROM trip_candidate tc
      JOIN attraction at2 ON at2.id = tc.attraction_id
      WHERE tc.trip_id = p.trip_id AND at2.sido_code = #{sidoCode}
  )

mapper.update:
UPDATE member_map_cover
SET focus_x = #{focusX}, focus_y = #{focusY}, zoom = #{zoom}
WHERE member_id = #{memberId} AND region_level = #{regionLevel} AND region_code = #{regionCode}
